    // Find holes.
    APInt Cur = Start;
    APInt DefStart, DefEnd;
    bool InDefault = false;
    bool FoundDefaultRange = false;
    while (Cur != End) {
      bool IsCase = false;
      for (ConstantInt *C : AllCases) {
        if (C->getValue() == Cur) {
          IsCase = true;
          break;
        }
      }
      if (!IsCase && !InDefault) {
        // Start of a default range.
        if (FoundDefaultRange) {
          // Already found a default range earlier, multiple disjoint default ranges.
          return false;
        }
        DefStart = Cur;
        InDefault = true;
        FoundDefaultRange = true;
      } else if (IsCase && InDefault) {
        // End of the current default range.
        DefEnd = Cur;
        InDefault = false;
        // Continue scanning; there may be cases after this default range.
      }
      ++Cur;
    }
    if (InDefault) {
      DefEnd = End;
    }
    if (!FoundDefaultRange || DefStart == DefEnd)
      return false;
CODEEOF"}

